def summarize(rows):
    count = len(rows)
    body = "# Trade Anomaly Detection Report\n\n"
    body += "**Validated alerts:** " + str(count) + "\n\n"
    if count > 0:
        body += "## Validated anomalies\n"
        for r in rows:
            body += "- Alert " + str(r.get("alert_id", "")) + ": " + str(r.get("trader_name", "")) + " (" + str(r.get("scenario", "")) + ")\n"
    else:
        body += "No significant trade anomalies passed validation.\n"
    return [{
        "title": "Trade Anomaly Report",
        "body_markdown": body,
        "anomalies_found_count": count,
    }]

